(function(){'use strict';function jumpToChapter(){var select=document.getElementById('chapter-select');if(select&&select.value){window.location.href=select.value;}}
function getScrollKey(novelSlug,chapterId){return'scroll_'+novelSlug+'_'+chapterId;}
function saveScrollPosition(novelSlug,chapterId){var scrollTop=window.pageYOffset||document.documentElement.scrollTop;var documentHeight=document.documentElement.scrollHeight-window.innerHeight;var scrollPercent=documentHeight>0?(scrollTop/documentHeight):0;localStorage.setItem(getScrollKey(novelSlug,chapterId),scrollPercent.toFixed(4));}
function restoreScrollPosition(novelSlug,chapterId){var urlParams=new URLSearchParams(window.location.search);if(urlParams.get('scroll')==='content')return;var saved=localStorage.getItem(getScrollKey(novelSlug,chapterId));if(saved){var scrollPercent=parseFloat(saved);var documentHeight=document.documentElement.scrollHeight-window.innerHeight;var targetScroll=scrollPercent*documentHeight;window.scrollTo(0,targetScroll);}}
function getNextUnreadChapter(novelSlug,allChapterIds,currentChapterId){var visitedKey='visited_'+novelSlug;var visitedChapters=JSON.parse(localStorage.getItem(visitedKey)||'{}');var currentIdx=allChapterIds.indexOf(currentChapterId);if(currentIdx===-1)return null;for(var i=currentIdx+1;i<allChapterIds.length;i++){var chId=allChapterIds[i];if(!visitedChapters[chId]||!visitedChapters[chId].completed){return chId;}}
for(var i=0;i<currentIdx;i++){var chId=allChapterIds[i];if(!visitedChapters[chId]||!visitedChapters[chId].completed){return chId;}}
return null;}
function setupAutoAdvance(novelSlug,chapterId,nextChapterId){if(!nextChapterId)return;if(localStorage.getItem('autoAdvance')!=='true')return;var originalMarkCompleted=window.markChapterCompleted;if(originalMarkCompleted){window.markChapterCompleted=function(ns,cid){originalMarkCompleted(ns,cid);if(ns===novelSlug&&cid===chapterId){setTimeout(function(){var url='../'+nextChapterId+'/';var autoScroll=localStorage.getItem('autoScrollToContent');if(autoScroll==='true'){url+='?scroll=content';}
window.location.href=url;},2000);}};}}
function initScrollPositionTracking(novelSlug,chapterId){var saveTimeout;window.addEventListener('scroll',function(){clearTimeout(saveTimeout);saveTimeout=setTimeout(function(){saveScrollPosition(novelSlug,chapterId);},500);});setTimeout(function(){restoreScrollPosition(novelSlug,chapterId);},200);}
window.jumpToChapter=jumpToChapter;window.saveScrollPosition=saveScrollPosition;window.restoreScrollPosition=restoreScrollPosition;window.getNextUnreadChapter=getNextUnreadChapter;window.setupAutoAdvance=setupAutoAdvance;window.initScrollPositionTracking=initScrollPositionTracking;})();